import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import {
  fetchAllPosts,
  createPost,
  updatePost,
  togglePublished,
  deletePost,
} from '../services/blogService';
import { BlogPost, BlogCategory } from '../types';
import { FileText, Plus, Trash2, Edit, Save, X, Eye, EyeOff } from 'lucide-react';
import toast from 'react-hot-toast';

const CATEGORIES: BlogCategory[] = [
  'Cibersegurança',
  'Desenvolvimento',
  'Angola Tech',
  'Tendências',
];

const slugify = (text: string) =>
  text
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');

export const AdminBlog: React.FC = () => {
  const queryClient = useQueryClient();
  const [isEditing, setIsEditing] = useState<boolean>(false);
  const [currentPost, setCurrentPost] = useState<Partial<BlogPost>>({});

  const { data: posts = [], isLoading } = useQuery({
    queryKey: ['admin-blog'],
    queryFn: fetchAllPosts,
  });

  const createMutation = useMutation({
    mutationFn: (data: Partial<BlogPost>) => createPost(data as any),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-blog'] });
      toast.success('Artigo criado com sucesso');
      setIsEditing(false);
      setCurrentPost({});
    },
    onError: () => toast.error('Erro ao criar artigo'),
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: Partial<BlogPost> }) => updatePost(id, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-blog'] });
      toast.success('Artigo atualizado');
      setIsEditing(false);
      setCurrentPost({});
    },
    onError: () => toast.error('Erro ao atualizar artigo'),
  });

  const publishMutation = useMutation({
    mutationFn: ({ id, published }: { id: string; published: boolean }) =>
      togglePublished(id, published),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['admin-blog'] }),
    onError: () => toast.error('Erro ao alterar visibilidade'),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => deletePost(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-blog'] });
      toast.success('Artigo eliminado');
    },
    onError: () => toast.error('Erro ao eliminar artigo'),
  });

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentPost.title || !currentPost.content || !currentPost.category) {
      toast.error('Preencha os campos obrigatórios');
      return;
    }

    // Auto-generate slug if not provided
    const payload = {
      ...currentPost,
      slug: currentPost.slug || slugify(currentPost.title),
    };

    if (currentPost.id) {
      updateMutation.mutate({ id: currentPost.id, data: payload });
    } else {
      createMutation.mutate(payload);
    }
  };

  if (isEditing) {
    return (
      <div className="bg-nxr-panel border border-nxr-border rounded-lg p-6">
        <div className="flex justify-between items-center mb-6 border-b border-slate-800 pb-4">
          <h2 className="text-xl font-bold text-white font-rajdhani flex items-center">
            {currentPost.id ? (
              <Edit className="w-5 h-5 mr-2 text-nxr-primary" />
            ) : (
              <Plus className="w-5 h-5 mr-2 text-nxr-primary" />
            )}
            {currentPost.id ? 'Editar Artigo' : 'Novo Artigo'}
          </h2>
          <button
            onClick={() => setIsEditing(false)}
            className="text-slate-400 hover:text-white transition-colors"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        <form onSubmit={handleSave} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">
                Título *
              </label>
              <input
                required
                type="text"
                value={currentPost.title || ''}
                onChange={e =>
                  setCurrentPost({
                    ...currentPost,
                    title: e.target.value,
                    slug: slugify(e.target.value),
                  })
                }
                className="w-full bg-slate-950 border border-slate-800 text-white px-4 py-2 focus:border-cyan-400 transition-colors"
              />
            </div>
            <div>
              <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">Slug</label>
              <input
                required
                type="text"
                value={currentPost.slug || ''}
                onChange={e => setCurrentPost({ ...currentPost, slug: e.target.value })}
                className="w-full bg-slate-900 border border-slate-800 text-slate-500 px-4 py-2 cursor-not-allowed"
                readOnly
              />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div>
              <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">
                Categoria *
              </label>
              <select
                required
                value={currentPost.category || ''}
                onChange={e =>
                  setCurrentPost({ ...currentPost, category: e.target.value as BlogCategory })
                }
                className="w-full bg-slate-950 border border-slate-800 text-white px-4 py-2 focus:border-cyan-400 transition-colors"
              >
                <option value="" disabled>
                  Selecionar...
                </option>
                {CATEGORIES.map(c => (
                  <option key={c} value={c}>
                    {c}
                  </option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">
                Tempo de Leitura (min)
              </label>
              <input
                type="number"
                min="1"
                value={currentPost.reading_time_minutes || 5}
                onChange={e =>
                  setCurrentPost({ ...currentPost, reading_time_minutes: parseInt(e.target.value) })
                }
                className="w-full bg-slate-950 border border-slate-800 text-white px-4 py-2 focus:border-cyan-400 transition-colors"
              />
            </div>
            <div>
              <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">
                URL da Imagem de Capa
              </label>
              <input
                type="text"
                placeholder="https://..."
                value={currentPost.cover_image || ''}
                onChange={e => setCurrentPost({ ...currentPost, cover_image: e.target.value })}
                className="w-full bg-slate-950 border border-slate-800 text-white px-4 py-2 focus:border-cyan-400 transition-colors"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">
              Resumo (Excerpt) *
            </label>
            <textarea
              required
              rows={2}
              value={currentPost.excerpt || ''}
              onChange={e => setCurrentPost({ ...currentPost, excerpt: e.target.value })}
              className="w-full bg-slate-950 border border-slate-800 text-white px-4 py-2 focus:border-cyan-400 transition-colors"
            />
          </div>

          <div>
            <label className="block text-xs font-mono text-slate-400 mb-2 uppercase flex justify-between">
              <span>Conteúdo (Markdown suportado) *</span>
              <a
                href="https://www.markdownguide.org/cheat-sheet/"
                target="_blank"
                rel="noopener noreferrer"
                className="text-cyan-400 hover:underline"
              >
                Guia de Markdown
              </a>
            </label>
            <textarea
              required
              rows={15}
              value={currentPost.content || ''}
              onChange={e => setCurrentPost({ ...currentPost, content: e.target.value })}
              className="w-full bg-slate-950 border border-slate-800 text-white px-4 py-4 focus:border-cyan-400 transition-colors font-mono text-sm"
              placeholder="# Título Principal&#10;&#10;Escreva o seu conteúdo aqui..."
            />
          </div>

          <div className="flex justify-end gap-4 border-t border-slate-800 pt-6">
            <button
              type="button"
              onClick={() => setIsEditing(false)}
              className="px-6 py-2 border border-slate-700 text-slate-300 hover:text-white transition-colors"
            >
              Cancelar
            </button>
            <button
              type="submit"
              disabled={createMutation.isPending || updateMutation.isPending}
              className="px-6 py-2 bg-cyan-400 text-slate-950 font-bold uppercase tracking-widest text-sm hover:bg-white transition-colors flex items-center disabled:opacity-50"
            >
              <Save className="w-4 h-4 mr-2" />
              {currentPost.id ? 'Atualizar Artigo' : 'Publicar Artigo'}
            </button>
          </div>
        </form>
      </div>
    );
  }

  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-xl font-bold text-white font-rajdhani flex items-center">
          <FileText className="mr-2 text-nxr-primary" />
          Gestão de Blog
        </h2>
        <button
          onClick={() => {
            setCurrentPost({});
            setIsEditing(true);
          }}
          className="flex items-center px-4 py-2 bg-nxr-primary text-nxr-dark font-bold text-sm hover:bg-cyan-300 transition-colors"
        >
          <Plus className="w-4 h-4 mr-2" />
          Novo Artigo
        </button>
      </div>

      <div className="bg-nxr-panel border border-nxr-border overflow-hidden rounded-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-slate-400">
            <thead className="bg-slate-900/50 text-xs uppercase font-mono text-slate-500 border-b border-nxr-border">
              <tr>
                <th className="px-6 py-4">Artigo</th>
                <th className="px-6 py-4">Categoria</th>
                <th className="px-6 py-4">Data de Criação</th>
                <th className="px-6 py-4">Estado</th>
                <th className="px-6 py-4 text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-nxr-border">
              {isLoading ? (
                <tr>
                  <td colSpan={5} className="px-6 py-8 text-center text-slate-500">
                    A carregar artigos...
                  </td>
                </tr>
              ) : posts.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-6 py-8 text-center text-slate-500">
                    Nenhum artigo encontrado. Crie o primeiro!
                  </td>
                </tr>
              ) : (
                posts.map(post => (
                  <tr key={post.id} className="hover:bg-slate-800/30 transition-colors">
                    <td className="px-6 py-4">
                      <div className="font-bold text-white mb-1">{post.title}</div>
                      <div className="text-xs font-mono text-slate-500 truncate max-w-xs">
                        {post.slug}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="px-2 py-1 bg-slate-800 text-cyan-400 text-xs rounded">
                        {post.category}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-xs font-mono">
                      {new Date(post.created_at).toLocaleDateString('pt-PT')}
                    </td>
                    <td className="px-6 py-4">
                      <button
                        onClick={() =>
                          publishMutation.mutate({ id: post.id, published: !post.published })
                        }
                        className={`flex items-center text-xs px-2 py-1 rounded border transition-colors ${
                          post.published
                            ? 'text-green-400 border-green-900 bg-green-900/20 hover:bg-green-900/40'
                            : 'text-slate-400 border-slate-700 bg-slate-800 hover:bg-slate-700'
                        }`}
                      >
                        {post.published ? (
                          <>
                            <Eye className="w-3 h-3 mr-1" /> Publicado
                          </>
                        ) : (
                          <>
                            <EyeOff className="w-3 h-3 mr-1" /> Rascunho
                          </>
                        )}
                      </button>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button
                        onClick={() => {
                          setCurrentPost(post);
                          setIsEditing(true);
                        }}
                        className="text-slate-400 hover:text-cyan-400 transition-colors mr-3"
                        title="Editar Artigo"
                      >
                        <Edit className="w-4 h-4" />
                      </button>
                      <button
                        onClick={() => {
                          if (confirm('Tem a certeza que deseja eliminar este artigo?'))
                            deleteMutation.mutate(post.id);
                        }}
                        className="text-slate-400 hover:text-red-500 transition-colors"
                        title="Eliminar Artigo"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Order } from '../types';
import { fetchAllOrdersAdmin, updateOrderStatus, updateOrderNotes } from '../services/storeService';
import { supabase } from '../lib/supabase';
import { Eye, MessageCircle, Mail, X, Save, Box } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminOrders: React.FC = () => {
  const queryClient = useQueryClient();
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [statusFilter, setStatusFilter] = useState<Order['status'] | 'all'>('all');
  const [internalNotes, setInternalNotes] = useState('');

  const { data: orders = [], isLoading } = useQuery({
    queryKey: ['admin-orders'],
    queryFn: fetchAllOrdersAdmin,
  });

  // Supabase Realtime Subscription for Orders
  useEffect(() => {
    const channel = supabase
      .channel('public:orders')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'orders' }, payload => {
        queryClient.invalidateQueries({ queryKey: ['admin-orders'] });
        toast('Nova requisição de compra recebida!', { icon: '🛍️' });
      })
      .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'orders' }, payload => {
        queryClient.invalidateQueries({ queryKey: ['admin-orders'] });
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [queryClient]);

  const updateStatusMutation = useMutation({
    mutationFn: ({ id, status }: { id: string; status: Order['status'] }) =>
      updateOrderStatus(id, status),
    onSuccess: (_, variables) => {
      toast.success('Status atualizado');
      queryClient.invalidateQueries({ queryKey: ['admin-orders'] });
      if (selectedOrder) {
        setSelectedOrder({ ...selectedOrder, status: variables.status });
      }
    },
    onError: err => toast.error(`Erro: ${(err as Error).message}`),
  });

  const updateNotesMutation = useMutation({
    mutationFn: ({ id, notes }: { id: string; notes: string }) => updateOrderNotes(id, notes),
    onSuccess: (_, variables) => {
      toast.success('Notas guardadas');
      queryClient.invalidateQueries({ queryKey: ['admin-orders'] });
      if (selectedOrder) {
        setSelectedOrder({ ...selectedOrder, notes: variables.notes });
      }
    },
    onError: err => toast.error(`Erro: ${(err as Error).message}`),
  });

  const stats = useMemo(() => ({
    total: orders.length,
    new: orders.filter(o => o.status === 'new').length,
    processing: orders.filter(o => o.status === 'processing').length,
    completed: orders.filter(o => o.status === 'completed').length,
  }), [orders]);

  const filteredOrders = statusFilter === 'all' ? orders : orders.filter(o => o.status === statusFilter);

  const getStatusInfo = (status: string) => {
    switch(status) {
      case 'new': return { label: 'Nova', color: 'bg-cyan-900/40 text-cyan-400 border-cyan-500/50' };
      case 'contacted': return { label: 'Contactado', color: 'bg-yellow-900/40 text-yellow-400 border-yellow-500/50' };
      case 'processing': return { label: 'Em Processo', color: 'bg-blue-900/40 text-blue-400 border-blue-500/50' };
      case 'completed': return { label: 'Concluída', color: 'bg-green-900/40 text-green-400 border-green-500/50' };
      case 'cancelled': return { label: 'Cancelada', color: 'bg-slate-800 text-slate-400 border-slate-700' };
      default: return { label: status, color: 'bg-slate-800 text-slate-400 border-slate-700' };
    }
  };

  const openOrderModal = (order: Order) => {
    setSelectedOrder(order);
    setInternalNotes(order.notes || '');
  };

  return (
    <div className="space-y-6">
      {/* Header & Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <div className="md:col-span-1 bg-slate-900 border border-slate-700 p-4 rounded-xl flex flex-col justify-center">
          <h2 className="text-xl font-bold text-white">Requisições</h2>
          <p className="text-sm text-slate-400">Gestão de encomendas da loja</p>
        </div>
        <div className="bg-slate-900 border-l-2 border-cyan-500 border-y border-r border-slate-700 p-4 rounded-xl">
          <div className="text-cyan-400 text-xs font-mono uppercase">Novas Requisições</div>
          <div className="text-3xl font-bold text-white mt-1">{stats.new}</div>
        </div>
        <div className="bg-slate-900 border border-slate-700 p-4 rounded-xl">
          <div className="text-blue-400 text-xs font-mono uppercase">Em Processo</div>
          <div className="text-3xl font-bold text-white mt-1">{stats.processing}</div>
        </div>
        <div className="bg-slate-900 border border-slate-700 p-4 rounded-xl">
          <div className="text-green-400 text-xs font-mono uppercase">Concluídas</div>
          <div className="text-3xl font-bold text-white mt-1">{stats.completed}</div>
        </div>
      </div>

      {/* Filters */}
      <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-thin scrollbar-thumb-slate-700">
        {[
          { value: 'all', label: 'Todas' },
          { value: 'new', label: 'Novas' },
          { value: 'contacted', label: 'Contactado' },
          { value: 'processing', label: 'Em Processo' },
          { value: 'completed', label: 'Concluídas' },
          { value: 'cancelled', label: 'Canceladas' }
        ].map(filter => (
          <button
            key={filter.value}
            onClick={() => setStatusFilter(filter.value as any)}
            className={`px-4 py-1.5 text-xs font-bold rounded-lg border transition-colors whitespace-nowrap ${
              statusFilter === filter.value
                ? 'bg-cyan-900 text-cyan-300 border-cyan-500'
                : 'bg-slate-900 text-slate-400 border-slate-700 hover:border-slate-500'
            }`}
          >
            {filter.label}
          </button>
        ))}
      </div>

      {/* Table */}
      <div className="bg-slate-900 border border-slate-700 rounded-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-slate-300">
            <thead className="bg-slate-950/50 text-xs uppercase font-mono text-slate-500 border-b border-slate-800">
              <tr>
                <th className="px-6 py-4">Data</th>
                <th className="px-6 py-4">Cliente</th>
                <th className="px-6 py-4">Produto</th>
                <th className="px-6 py-4 text-center">Origem</th>
                <th className="px-6 py-4 text-center">Status</th>
                <th className="px-6 py-4 text-right">Acções</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-800">
              {isLoading ? (
                <tr><td colSpan={6} className="px-6 py-12 text-center text-slate-500">A carregar requisições...</td></tr>
              ) : filteredOrders.length === 0 ? (
                <tr><td colSpan={6} className="px-6 py-12 text-center text-slate-500">Nenhuma requisição encontrada.</td></tr>
              ) : (
                filteredOrders.map(order => {
                  const statusInfo = getStatusInfo(order.status);
                  return (
                    <tr key={order.id} className={`hover:bg-slate-800/30 transition-colors ${order.status === 'new' ? 'bg-cyan-950/10 border-l-2 border-l-cyan-400' : ''}`}>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="text-xs text-slate-400">{new Date(order.created_at).toLocaleDateString()}</div>
                        <div className="text-[10px] text-slate-500 font-mono">{new Date(order.created_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="font-medium text-white">{order.customer_name}</div>
                        <div className="text-xs text-slate-400">{order.customer_email}</div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="font-medium text-slate-300 line-clamp-1 max-w-[200px]" title={order.product_name}>
                          {order.quantity}x {order.product_name}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span className={`inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${
                          order.source === 'whatsapp' ? 'bg-green-900/30 text-green-400' : 'bg-blue-900/30 text-blue-400'
                        }`}>
                          {order.source === 'whatsapp' ? '💬 WhatsApp' : '📋 Formulário'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span className={`inline-block px-2.5 py-1 rounded-full text-xs font-bold border ${statusInfo.color}`}>
                          {statusInfo.label}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button
                          onClick={() => openOrderModal(order)}
                          className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 border border-slate-600 text-white text-xs font-medium rounded transition-colors"
                        >
                          <Eye className="w-3.5 h-3.5" /> Detalhes
                        </button>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Detalhes Modal */}
      {selectedOrder && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-700 w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-6 border-b border-slate-800 bg-slate-950/50">
              <h3 className="text-xl font-bold text-white flex items-center gap-2">
                <Box className="w-5 h-5 text-cyan-400" /> Detalhes da Requisição
              </h3>
              <button onClick={() => setSelectedOrder(null)} className="text-slate-400 hover:text-white transition-colors">
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="p-6 overflow-y-auto">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                <div className="space-y-4">
                  <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700/50">
                    <h4 className="text-[10px] font-mono text-slate-500 uppercase tracking-widest mb-3">Dados do Cliente</h4>
                    <p className="text-white font-medium">{selectedOrder.customer_name}</p>
                    <p className="text-slate-400 text-sm mt-1">{selectedOrder.customer_email}</p>
                    {selectedOrder.customer_phone && (
                      <p className="text-slate-400 text-sm mt-1 font-mono">{selectedOrder.customer_phone}</p>
                    )}
                  </div>

                  <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700/50">
                    <h4 className="text-[10px] font-mono text-slate-500 uppercase tracking-widest mb-3">Pedido via {selectedOrder.source}</h4>
                    <div className="flex items-center gap-2">
                      <div className="w-8 h-8 rounded bg-slate-700 flex items-center justify-center shrink-0">
                        {/* selectedOrder.products is joined via relation, if available */}
                        {(selectedOrder as any).products?.cover_image ? 
                          <img src={(selectedOrder as any).products.cover_image} className="w-full h-full object-cover rounded" alt="cover"/> :
                          <Box className="w-4 h-4 text-slate-500" />
                        }
                      </div>
                      <div>
                        <p className="text-white font-medium text-sm leading-tight">{selectedOrder.product_name}</p>
                        <p className="text-slate-400 text-xs mt-0.5">{selectedOrder.quantity}x • {selectedOrder.product_price ? `Preço un: ${selectedOrder.product_price.toLocaleString('pt-AO')}` : 'Sob consulta'}</p>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="space-y-4">
                  <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700/50">
                    <h4 className="text-[10px] font-mono text-slate-500 uppercase tracking-widest mb-3">Gerir Status</h4>
                    <select
                      value={selectedOrder.status}
                      onChange={(e) => updateStatusMutation.mutate({ id: selectedOrder.id, status: e.target.value as Order['status'] })}
                      className="w-full bg-slate-900 border border-slate-700 text-white px-3 py-2 text-sm rounded focus:outline-none focus:border-cyan-500"
                    >
                      <option value="new">Nova (Pendente)</option>
                      <option value="contacted">Contactado</option>
                      <option value="processing">Em Processo</option>
                      <option value="completed">Concluída</option>
                      <option value="cancelled">Cancelada</option>
                    </select>
                  </div>

                  <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700/50 flex flex-col gap-2">
                    <h4 className="text-[10px] font-mono text-slate-500 uppercase tracking-widest mb-1">Contactar</h4>
                    <a
                      href={`https://wa.me/${selectedOrder.customer_phone?.replace(/\D/g, '') || ''}?text=Olá ${selectedOrder.customer_name}, contactamos da NXRSCRIPTS relativamente à sua requisição do produto ${selectedOrder.product_name}.`}
                      target="_blank" rel="noreferrer"
                      className="flex items-center justify-center gap-2 w-full py-2 bg-green-600 hover:bg-green-500 text-white text-sm font-medium rounded transition-colors"
                    >
                      <MessageCircle className="w-4 h-4" /> WhatsApp
                    </a>
                    <a
                      href={`mailto:${selectedOrder.customer_email}?subject=A sua requisição na NXRSCRIPTS - ${selectedOrder.product_name}`}
                      className="flex items-center justify-center gap-2 w-full py-2 bg-slate-700 hover:bg-slate-600 text-white text-sm font-medium rounded transition-colors"
                    >
                      <Mail className="w-4 h-4" /> Email
                    </a>
                  </div>
                </div>
              </div>

              {selectedOrder.message && (
                <div className="bg-slate-800/30 p-4 rounded-xl border border-slate-700/30 mb-6">
                  <h4 className="text-[10px] font-mono text-slate-500 uppercase tracking-widest mb-2">Mensagem do Cliente</h4>
                  <p className="text-slate-300 text-sm italic border-l-2 border-slate-600 pl-3">"{selectedOrder.message}"</p>
                </div>
              )}

              <div className="space-y-2">
                <label className="text-[10px] font-mono text-slate-500 uppercase tracking-widest">Notas Internas da Equipa (Invisível ao cliente)</label>
                <textarea
                  value={internalNotes}
                  onChange={e => setInternalNotes(e.target.value)}
                  rows={3}
                  className="w-full bg-slate-900 border border-slate-700 text-slate-300 px-3 py-2 text-sm rounded focus:outline-none focus:border-cyan-500"
                  placeholder="Ex: Produto encomendado ao fornecedor em X data..."
                />
                <button
                  onClick={() => updateNotesMutation.mutate({ id: selectedOrder.id, notes: internalNotes })}
                  disabled={updateNotesMutation.isPending || internalNotes === selectedOrder.notes}
                  className="flex items-center gap-2 px-4 py-1.5 bg-slate-800 text-cyan-400 text-xs font-bold uppercase rounded border border-slate-700 hover:bg-slate-700 hover:border-cyan-500/50 disabled:opacity-50 transition-colors"
                >
                  <Save className="w-3.5 h-3.5" /> Gravar Notas
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Product, NewProduct } from '../types';
import {
  fetchAllProductsAdmin,
  createProduct,
  updateProduct,
  deleteProduct,
  toggleProductActive,
  uploadProductImage,
  getCategoryList,
} from '../services/storeService';
import { Pencil, Trash2, Image as ImageIcon, X, Plus, Loader2, Star } from 'lucide-react';
import toast from 'react-hot-toast';

const INITIAL_FORM_STATE: Partial<Product> = {
  name: '',
  category: '',
  price: undefined,
  currency: 'AOA',
  stock_status: 'available',
  sort_order: 0,
  description: '',
  featured: false,
  active: true,
  tags: [],
  specs: {},
  images: [],
  cover_image: '',
};

export const AdminProducts: React.FC = () => {
  const queryClient = useQueryClient();
  const [showForm, setShowForm] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [formData, setFormData] = useState<Partial<Product>>(INITIAL_FORM_STATE);
  const [tagsInput, setTagsInput] = useState('');
  const [specsInput, setSpecsInput] = useState('');
  const [pendingImages, setPendingImages] = useState<File[]>([]);
  const [uploadingImages, setUploadingImages] = useState(false);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);

  const categories = getCategoryList().filter(c => c !== 'Todos');

  const { data: products = [], isLoading } = useQuery({
    queryKey: ['admin-products'],
    queryFn: fetchAllProductsAdmin,
  });

  const invalidate = () => queryClient.invalidateQueries({ queryKey: ['admin-products'] });

  const createMutation = useMutation({
    mutationFn: createProduct,
    onSuccess: async newProduct => {
      if (pendingImages.length > 0) {
        await handleImageUploads(newProduct.id);
      }
      toast.success('Produto criado com sucesso');
      closeForm();
      invalidate();
    },
    onError: err => toast.error(`Erro ao criar: ${(err as Error).message}`),
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: Partial<Product> }) => updateProduct(id, data),
    onSuccess: () => {
      toast.success('Produto atualizado com sucesso');
      closeForm();
      invalidate();
    },
    onError: err => toast.error(`Erro ao atualizar: ${(err as Error).message}`),
  });

  const deleteMutation = useMutation({
    mutationFn: deleteProduct,
    onSuccess: () => {
      toast.success('Produto eliminado');
      invalidate();
    },
    onError: err => toast.error(`Erro ao eliminar: ${(err as Error).message}`),
  });

  const toggleActiveMutation = useMutation({
    mutationFn: ({ id, active }: { id: string; active: boolean }) =>
      toggleProductActive(id, active),
    onSuccess: () => invalidate(),
  });

  const toggleFeaturedMutation = useMutation({
    mutationFn: ({ id, featured }: { id: string; featured: boolean }) =>
      updateProduct(id, { featured }),
    onSuccess: () => invalidate(),
  });

  const handleEdit = (product: Product) => {
    setEditingProduct(product);
    setFormData(product);
    setTagsInput(product.tags?.join(', ') || '');
    const specsStr = product.specs
      ? Object.entries(product.specs)
          .map(([k, v]) => `${k}: ${v}`)
          .join('\n')
      : '';
    setSpecsInput(specsStr);
    setPendingImages([]);
    setShowForm(true);
  };

  const closeForm = () => {
    setShowForm(false);
    setEditingProduct(null);
    setFormData(INITIAL_FORM_STATE);
    setTagsInput('');
    setSpecsInput('');
    setPendingImages([]);
  };

  const handleImageUploads = async (productId: string) => {
    setUploadingImages(true);
    try {
      const urls: string[] = [];
      for (const file of pendingImages) {
        const url = await uploadProductImage(file, productId);
        urls.push(url);
      }

      if (urls.length > 0) {
        const existingImages = formData.images || [];
        const newImages = [...existingImages, ...urls];
        const updates: Partial<Product> = { images: newImages };
        if (!formData.cover_image && urls.length > 0) {
          updates.cover_image = urls[0];
        }
        await updateProduct(productId, updates);
      }
    } catch (err) {
      toast.error('Erro ao fazer upload de imagens');
    } finally {
      setUploadingImages(false);
    }
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const files = Array.from(e.target.files);

    const validFiles = files.filter(f => {
      if (!f.type.startsWith('image/')) {
        toast.error(`${f.name} não é uma imagem válida.`);
        return false;
      }
      if (f.size > 5 * 1024 * 1024) {
        toast.error(`${f.name} excede o limite de 5MB.`);
        return false;
      }
      return true;
    });

    if (editingProduct) {
      setUploadingImages(true);
      try {
        const urls: string[] = [];
        for (const file of validFiles) {
          const url = await uploadProductImage(file, editingProduct.id);
          urls.push(url);
        }
        const newImages = [...(formData.images || []), ...urls];
        setFormData({
          ...formData,
          images: newImages,
          cover_image: formData.cover_image || urls[0],
        });
      } catch (err) {
        toast.error('Erro ao fazer upload');
      } finally {
        setUploadingImages(false);
      }
    } else {
      setPendingImages(prev => [...prev, ...validFiles]);
    }
  };

  const removeImage = (urlToRemove: string) => {
    const newImages = (formData.images || []).filter(url => url !== urlToRemove);
    setFormData({
      ...formData,
      images: newImages,
      cover_image: formData.cover_image === urlToRemove ? newImages[0] || '' : formData.cover_image,
    });
  };

  const removePendingImage = (idx: number) => {
    setPendingImages(prev => prev.filter((_, i) => i !== idx));
  };

  const onSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.category || !formData.description) {
      toast.error('Preencha os campos obrigatórios (*)');
      return;
    }

    const tags = tagsInput
      .split(',')
      .map(t => t.trim())
      .filter(Boolean);

    const specs: Record<string, string> = {};
    specsInput.split('\n').forEach(line => {
      const parts = line.split(':');
      if (parts.length >= 2) {
        const key = parts[0].trim();
        const val = parts.slice(1).join(':').trim();
        if (key && val) specs[key] = val;
      }
    });

    const payload: Partial<Product> = {
      ...formData,
      tags,
      specs,
      price: formData.price === '' ? null : Number(formData.price) || null,
      sort_order: Number(formData.sort_order) || 0,
    };

    if (editingProduct) {
      updateMutation.mutate({ id: editingProduct.id, data: payload });
    } else {
      createMutation.mutate(payload as NewProduct);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-slate-900 border border-slate-700 p-4 rounded-xl">
        <div>
          <h2 className="text-xl font-bold text-white">Gestão de Produtos</h2>
          <p className="text-sm text-slate-400">
            {products.length} total · {products.filter(p => p.active).length} activos
          </p>
        </div>
        {!showForm && (
          <button
            onClick={() => setShowForm(true)}
            className="flex items-center gap-2 bg-cyan-600 hover:bg-cyan-500 text-white px-4 py-2 rounded-lg font-medium transition-colors"
          >
            <Plus className="w-4 h-4" /> Novo Produto
          </button>
        )}
      </div>

      {showForm && (
        <form
          onSubmit={onSubmit}
          className="bg-slate-900 border border-cyan-500/50 p-6 rounded-xl space-y-6 shadow-xl shadow-cyan-900/10"
        >
          <div className="flex justify-between items-center border-b border-slate-800 pb-4">
            <h3 className="text-lg font-bold text-white">
              {editingProduct ? 'Editar Produto' : 'Novo Produto'}
            </h3>
            <button
              type="button"
              onClick={closeForm}
              className="text-slate-400 hover:text-white p-1"
            >
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-medium text-slate-400 mb-1">Nome *</label>
                <input
                  type="text"
                  required
                  value={formData.name || ''}
                  onChange={e => setFormData({ ...formData, name: e.target.value })}
                  className="w-full bg-slate-800 border border-slate-700 text-white px-3 py-2 rounded focus:outline-none focus:border-cyan-500"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-medium text-slate-400 mb-1">Categoria *</label>
                  <select
                    required
                    value={formData.category || ''}
                    onChange={e => setFormData({ ...formData, category: e.target.value })}
                    className="w-full bg-slate-800 border border-slate-700 text-white px-3 py-2 rounded focus:outline-none focus:border-cyan-500"
                  >
                    <option value="" disabled>
                      Selecione...
                    </option>
                    {categories.map(c => (
                      <option key={c} value={c}>
                        {c}
                      </option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-medium text-slate-400 mb-1">Status</label>
                  <select
                    value={formData.stock_status || 'available'}
                    onChange={e => setFormData({ ...formData, stock_status: e.target.value })}
                    className="w-full bg-slate-800 border border-slate-700 text-white px-3 py-2 rounded focus:outline-none focus:border-cyan-500"
                  >
                    <option value="available">Disponível</option>
                    <option value="out_of_stock">Esgotado</option>
                    <option value="on_request">Sob Encomenda</option>
                  </select>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-medium text-slate-400 mb-1">Preço</label>
                  <input
                    type="number"
                    step="0.01"
                    placeholder="Vazio = Consulte-nos"
                    value={formData.price || ''}
                    onChange={e => setFormData({ ...formData, price: e.target.value })}
                    className="w-full bg-slate-800 border border-slate-700 text-white px-3 py-2 rounded focus:outline-none focus:border-cyan-500"
                  />
                </div>
                <div>
                  <label className="block text-xs font-medium text-slate-400 mb-1">Moeda</label>
                  <select
                    value={formData.currency || 'AOA'}
                    onChange={e => setFormData({ ...formData, currency: e.target.value })}
                    className="w-full bg-slate-800 border border-slate-700 text-white px-3 py-2 rounded focus:outline-none focus:border-cyan-500"
                  >
                    <option value="AOA">AOA (Kwanza)</option>
                    <option value="USD">USD (Dólar)</option>
                  </select>
                </div>
              </div>
              <div>
                <label className="block text-xs font-medium text-slate-400 mb-1">Ordem de Exibição</label>
                <input
                  type="number"
                  value={formData.sort_order || 0}
                  onChange={e => setFormData({ ...formData, sort_order: e.target.value })}
                  className="w-full bg-slate-800 border border-slate-700 text-white px-3 py-2 rounded focus:outline-none focus:border-cyan-500"
                />
              </div>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-xs font-medium text-slate-400 mb-1">Descrição *</label>
                <textarea
                  required
                  rows={4}
                  value={formData.description || ''}
                  onChange={e => setFormData({ ...formData, description: e.target.value })}
                  className="w-full bg-slate-800 border border-slate-700 text-white px-3 py-2 rounded focus:outline-none focus:border-cyan-500"
                />
              </div>
              <div>
                <label className="block text-xs font-medium text-slate-400 mb-1">Tags</label>
                <input
                  type="text"
                  placeholder="hardware, servidor, rede (separados por vírgula)"
                  value={tagsInput}
                  onChange={e => setTagsInput(e.target.value)}
                  className="w-full bg-slate-800 border border-slate-700 text-white px-3 py-2 rounded focus:outline-none focus:border-cyan-500"
                />
              </div>
              <div>
                <label className="block text-xs font-medium text-slate-400 mb-1">Especificações Técnicas</label>
                <textarea
                  rows={3}
                  placeholder="Formato Chave: Valor (uma por linha)"
                  value={specsInput}
                  onChange={e => setSpecsInput(e.target.value)}
                  className="w-full bg-slate-800 border border-slate-700 text-white px-3 py-2 rounded focus:outline-none focus:border-cyan-500 font-mono text-sm"
                />
              </div>
              <div className="flex gap-6 mt-2">
                <label className="flex items-center gap-2 text-sm text-slate-300 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={formData.featured || false}
                    onChange={e => setFormData({ ...formData, featured: e.target.checked })}
                    className="rounded bg-slate-800 border-slate-700 text-cyan-500 focus:ring-cyan-500"
                  />
                  Produto em Destaque
                </label>
                <label className="flex items-center gap-2 text-sm text-slate-300 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={formData.active !== false}
                    onChange={e => setFormData({ ...formData, active: e.target.checked })}
                    className="rounded bg-slate-800 border-slate-700 text-cyan-500 focus:ring-cyan-500"
                  />
                  Activo na loja
                </label>
              </div>
            </div>
          </div>

          <div className="border-t border-slate-800 pt-6">
            <label className="block text-sm font-medium text-white mb-3">Imagens do Produto</label>
            <div className="relative border-2 border-dashed border-slate-700 hover:border-cyan-500 rounded-xl p-8 text-center transition-colors">
              <input
                type="file"
                multiple
                accept="image/jpeg,image/png,image/webp,image/gif"
                onChange={handleFileSelect}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                disabled={uploadingImages}
              />
              <ImageIcon className="w-10 h-10 text-slate-500 mx-auto mb-2" />
              <p className="text-slate-300 font-medium">Arrasta imagens aqui ou clica para seleccionar</p>
              <p className="text-slate-500 text-xs mt-1">JPG, PNG, WebP · máx 5MB por imagem</p>

              {uploadingImages && (
                <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm flex items-center justify-center rounded-xl z-10">
                  <Loader2 className="w-8 h-8 text-cyan-400 animate-spin" />
                </div>
              )}
            </div>

            {/* Imagens Existentes (Online) */}
            {formData.images && formData.images.length > 0 && (
              <div className="flex flex-wrap gap-3 mt-4">
                {formData.images.map((url, idx) => (
                  <div key={idx} className={`relative w-20 h-20 rounded-lg overflow-hidden border-2 ${formData.cover_image === url ? 'border-cyan-400' : 'border-slate-700'}`}>
                    <img src={url} alt="Prod" className="w-full h-full object-cover" />
                    {formData.cover_image === url && (
                      <span className="absolute bottom-0 inset-x-0 bg-cyan-500/80 text-[8px] text-white text-center font-bold uppercase py-0.5">Principal</span>
                    )}
                    <button
                      type="button"
                      onClick={() => removeImage(url)}
                      className="absolute top-1 right-1 bg-red-500/80 hover:bg-red-500 text-white rounded-full p-0.5 backdrop-blur-sm"
                    >
                      <X className="w-3 h-3" />
                    </button>
                    {formData.cover_image !== url && (
                      <button
                        type="button"
                        onClick={() => setFormData({...formData, cover_image: url})}
                        className="absolute bottom-1 left-1 bg-slate-900/80 hover:bg-cyan-500 text-white rounded p-0.5 text-[8px] uppercase backdrop-blur-sm transition-colors"
                      >
                        Tornar Principal
                      </button>
                    )}
                  </div>
                ))}
              </div>
            )}

            {/* Imagens Pendentes (Locais, antes do envio) */}
            {pendingImages.length > 0 && (
              <div className="flex flex-wrap gap-3 mt-4 pt-4 border-t border-slate-800">
                <p className="w-full text-xs text-slate-500 font-medium">Por enviar:</p>
                {pendingImages.map((file, idx) => (
                  <div key={idx} className="relative w-20 h-20 rounded-lg overflow-hidden border-2 border-yellow-500/50 opacity-80">
                    <img src={URL.createObjectURL(file)} alt="Pending" className="w-full h-full object-cover" />
                    <button
                      type="button"
                      onClick={() => removePendingImage(idx)}
                      className="absolute top-1 right-1 bg-red-500/80 hover:bg-red-500 text-white rounded-full p-0.5"
                    >
                      <X className="w-3 h-3" />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="flex justify-end gap-3 pt-4 border-t border-slate-800">
            <button
              type="button"
              onClick={closeForm}
              className="px-6 py-2 border border-slate-700 text-slate-300 rounded-lg hover:bg-slate-800 transition-colors"
            >
              Cancelar
            </button>
            <button
              type="submit"
              disabled={createMutation.isPending || updateMutation.isPending || uploadingImages}
              className="px-6 py-2 bg-cyan-600 hover:bg-cyan-500 text-white font-medium rounded-lg transition-colors flex items-center"
            >
              {(createMutation.isPending || updateMutation.isPending) ? (
                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
              ) : null}
              Guardar Produto
            </button>
          </div>
        </form>
      )}

      <div className="bg-slate-900 border border-slate-700 rounded-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-slate-300">
            <thead className="bg-slate-950/50 text-xs uppercase font-mono text-slate-500 border-b border-slate-800">
              <tr>
                <th className="px-6 py-4">Produto</th>
                <th className="px-6 py-4">Categoria</th>
                <th className="px-6 py-4">Preço</th>
                <th className="px-6 py-4 text-center">Stock</th>
                <th className="px-6 py-4 text-center">Visível</th>
                <th className="px-6 py-4 text-center">Destaque</th>
                <th className="px-6 py-4 text-right">Acções</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-800">
              {isLoading ? (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-slate-500">
                    <Loader2 className="w-6 h-6 animate-spin mx-auto mb-2" />
                    A carregar produtos...
                  </td>
                </tr>
              ) : products.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-slate-500">
                    Nenhum produto cadastrado. Adicione o primeiro produto.
                  </td>
                </tr>
              ) : (
                products.map(product => (
                  <tr key={product.id} className="hover:bg-slate-800/30 transition-colors">
                    <td className="px-6 py-3">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded bg-slate-800 flex-shrink-0 flex items-center justify-center overflow-hidden border border-slate-700">
                          {product.cover_image ? (
