  ShoppingBag,
  ArrowRight,
  ShieldCheck,
  Laptop,
  MonitorPlay,
  Router,
  Briefcase,
  Cpu,
  MousePointer2,
  HardDrive,
  Box,
} from 'lucide-react';
import { SEOHead } from '../components/SEOHead';
import { SEO_PAGES } from '../lib/seo';
